# Each publisher knows how to render its own preview
class LinkedInPublisher(Publisher):
    def render_preview(self, text: str, profile: dict) -> str:
        return f"""<div class="linkedin-card">...</div>"""

class GhostBlogPublisher(Publisher):
    def render_preview(self, text: str, profile: dict) -> str:
        return f"""<article class="blog-post">...</article>"""

